#include <algorithm>
#include <queue>
#include <tuple>

using namespace std;

// Function to check if a path exists from source to target with at most k heavy edges
// given a specific threshold.
bool can_reach(int n, const vector<tuple<int, int, int>>& edges, int source, int target, int k, int threshold) {
    // State: {nodes, heavy_edges_used}
    // We use a modified BFS/Dijkstra approach where the state includes the number of heavy edges used.
    // dist[i][j] = minimum number of edges to reach node i using exactly j heavy edges.
    // Since we only care about reachability, we can use a boolean or track the minimum.
    // Here, we track the minimum number of heavy edges to reach a node, but that's complex.
    // A simpler approach is to use BFS/Dijkstra on the state space (node, heavy_count).

    // dist[i][j] = minimum cost (or just visited status) to reach node i using AT MOST j heavy edges.
    // Since we are minimizing threshold, and the check function is monotonic, we only need reachability.

    // Let dist[i][j] be true if node i is reachable using at most j heavy edges.
    // Since the graph is unweighted in terms of path length (we just count edges), BFS is appropriate.

    // dp[i][j]: boolean, true if node i is reachable using at most j heavy edges.
    vector<vector<bool>> dp(n, vector<bool>(k + 1, false));

    // Queue for BFS: {node, heavy_edges_used}
    queue<pair<int, int>> q;

    dp[source][0] = true;
    q.push({source, 0});

    while (!q.empty()) {
        pair<int, int> current = q.front();
        q.pop();
        int u = current.first;
        int heavy_count = current.second;

        if (u == target) {
            // Optimization: if we found a path, we can stop early, but the BFS structure ensures we explore all reachable states.
            // Since we only need existence, this is fine.
        }

        // Iterate over all edges connected to u
        for (const auto& edge : edges) {
            int u1, v1, w;
            tie(u1, v1, w) = edge;

            int v = -1;
            if (u1 == u) v = v1;
            else if (v1 == u) v = u1;
            else continue; // Edge doesn't involve u

            int new_heavy_count = heavy_count + (w > threshold ? 1 : 0);

            if (new_heavy_count <= k) {
                if (!dp[v][new_heavy_count]) {
                    dp[v][new_heavy_count] = true;
                    q.push({v, new_heavy_count});
                }
            }
        }
    }

    // Check if the target is reachable with at most k heavy edges
    for (int j = 0; j <= k; ++j) {
        if (dp[target][j]) {
            return true;
        }
    }
    return false;
}

/**
 * @brief Returns the minimum integer threshold such that there exists a path from source to target 
 *        using at most k heavy edges.
 * 
 * @param n The number of nodes.
 * @param edges The list of edges [u, v, w].
 * @param source The starting node.
 * @param target The destination node.
 * @param k The maximum allowed number of heavy edges.
 * @return The minimum threshold, or -1 if no such path exists.
 */
int64 solve(int64 n_long, vector<vector<int64>>& edges_long, int64 source_long, int64 target_long, int64 k_long) {
    int n = (int)n_long;
    int source = (int)source_long;
    int target = (int)target_long;
    int k = (int)k_long;

    // Convert input types to use in helper function
    vector<tuple<int, int, int>> edges_tuple;
    vector<int> all_weights;
    for (const auto& edge_long : edges_long) {
        int u = (int)edge_long[0];
        int v = (int)edge_long[1];
        int w = (int)edge_long[2];
        edges_tuple.emplace_back(u, v, w);
        all_weights.push_back(w);
    }

    if (source == target) {
        return 0;
    }

    // Collect all unique edge weights to form the search space for binary search.
    // The possible thresholds are related to the edge weights.
    // The critical thresholds are: w (making edge light) and w-1 (making edge heavy).
    // We consider thresholds in the set {0} U {w | w is an edge weight} U {w-1 | w is an edge weight and w > 0}.

    vector<int> possible_thresholds = {0};
    for (int w : all_weights) {
        possible_thresholds.push_back(w);
        if (w > 0) {
            possible_thresholds.push_back(w - 1);
        }
    }

    // Sort and unique the thresholds
    sort(possible_thresholds.begin(), possible_thresholds.end());
    possible_thresholds.erase(unique(possible_thresholds.begin(), possible_thresholds.end()), possible_thresholds.end());

    // Binary search over the set of critical thresholds
    int64 min_threshold = -1;
    int low = 0;
    int high = possible_thresholds.size() - 1;

    // A very large threshold (larger than any edge weight) must be tested if the initial check fails.
    // The maximum possible weight is 10^9. Let's add this as a potential upper bound check.
    if (!possible_thresholds.empty()) {
        // The maximum weight in the graph is a safe upper bound for the binary search range if we use weight values.
        // If we use the collected thresholds, we should check the largest one, which might be the max weight.
        // If the largest weight fails, no larger weight will succeed, but we must ensure all weights up to 10^9 are covered implicitly.
    } else {
        // No edges, only possible if N=1 or source!=target and no path exists.
        return -1; 
    }


    // We perform binary search over the *indices* of possible_thresholds.
    while (low <= high) {
        int mid_idx = low + (high - low) / 2;
        int current_threshold = possible_thresholds[mid_idx];

        if (can_reach(n, edges_tuple, source, target, k, current_threshold)) {
            // Success: This threshold works. Try for a smaller one.
            min_threshold = current_threshold;
            high = mid_idx - 1;
        } else {
            // Failure: This threshold is too small (too many heavy edges). Need a larger threshold.
            low = mid_idx + 1;
        }
    }

    // Final check: If min_threshold is still -1, we must check if any threshold larger than the max edge weight works.
    // Since increasing the threshold never increases the number of heavy edges, if the largest candidate fails, no other threshold works.
    // The largest candidate in possible_thresholds is max(all_weights).
    if (min_threshold == -1) {
        // Check the absolute largest weight + 1 as a sanity check if necessary, 
        // but based on the problem structure, if the largest weight fails, nothing works.
        // The binary search covers all relevant weight boundaries.

        // A final check with a very large threshold (10^9 + 1) covers the case where all edges are light.
        // If this still fails, it means the graph is disconnected.
        if (can_reach(n, edges_tuple, source, target, k, 1000000001)) {
             // This case should have been caught by the binary search if 10^9+1 was implicitly covered or if the graph is connected.
             // Since we are seeking the *minimum* threshold, if the largest threshold works, min_threshold should have been set to the smallest possible weight that works.
             // If we reach here, it means even the largest weight threshold didn't satisfy the condition, implying no path exists.
             return -1;
        } else {
             return -1;
        }
    }


    return min_threshold;
}
